 1→import { Inject, Injectable } from '@nestjs/common';
 2→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
 3→import { Db } from '@shared/database/types';
 4→import { Cache } from '@podkopaev-tech/nest-infra-modules';
 5→import { SupportedNetworks } from '@modules/networks/types/network.type';
 6→import { Selectable } from 'kysely';
 7→import { CurrencyEntity } from '@entities/balance.entity';
 8→import { UUID } from 'crypto';
 9→import Decimal from 'decimal.js';
10→import { CurrencyRatesService } from './currency-rates.service';
11→
12→@Injectable()
13→export class CurrencyService {
14→  constructor(
15→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
16→    private readonly currencyRatesService: CurrencyRatesService,
17→  ) {}
18→
19→  @Cache({})
20→  async getCurrencies(filter?: {
21→    network?: SupportedNetworks;
22→  }): Promise<Selectable<CurrencyEntity>[]> {
23→    let query = this.db.selectFrom('currency').selectAll();
24→
25→    if (filter?.network) {
26→      query = query.where('network', '=', filter.network);
27→    }
28→
29→    return query.execute();
30→  }
31→  /**
32→   * Gets a currency by its code and network
33→   * @param code Currency code (e.g., 'USDT', 'TRX', 'ETH')
34→   * @param network Network (e.g., 'Tron', 'Ethereum')
35→   * @returns Currency DTO or undefined if not found
36→   */
37→  @Cache({
38→    ttl: 60_000, // 1 minute
39→  })
40→  async getCurrencyByCodeAndNetwork(
41→    code: string,
42→    network: SupportedNetworks,
43→  ): Promise<Selectable<CurrencyEntity> | undefined> {
44→    const currency = await this.db
45→      .selectFrom('currency')
46→      .selectAll()
47→      .where('code', '=', code)
48→      .where('network', '=', network)
49→      .executeTakeFirst();
50→
51→    return currency;
52→  }
53→
54→  async getCurrencyById(id: UUID): Promise<Selectable<CurrencyEntity>> {
55→    return await this.db
56→      .selectFrom('currency')
57→      .selectAll()
58→      .where('id', '=', id)
59→      .executeTakeFirstOrThrow();
60→  }
61→
62→  async amountToUSD(
63→    amount: string,
64→    currencyCode: string,
65→    decimalPlaces: number = 2,
66→  ): Promise<string> {
67→    const rate = await this.currencyRatesService.rateInUSD(currencyCode);
68→    console.log({ amount, rate });
69→    return new Decimal(amount)
70→      .div(rate)
71→      .toDecimalPlaces(decimalPlaces)
72→      .toString();
73→  }
74→}
