 9→export class DatabaseModule {
10→  static forRoot(): DynamicModule {
11→    return {
12→      module: DatabaseModule,
13→      providers: [
14→        {
15→          provide: DATABASE_CONNECTION_TOKEN,
16→          useFactory: async (config: ConfigType<typeof dbConfig>) => {
17→            const dialect = new PostgresDialect({
18→              pool: new Pool({
19→                database: config.database,
20→                host: config.host,
21→                user: config.user,
22→                port: config.port,
23→                password: config.password,
24→                max: 10,
25→              }),
26→            });
27→
28→            const db = new Kysely<Database>({
29→              dialect,
30→              plugins: [new CamelCasePlugin()],
31→            });
32→
33→            return db;
34→          },
35→          inject: [dbConfig.KEY],
36→        },
37→      ],
38→      exports: [DATABASE_CONNECTION_TOKEN],
39→    };
40→  }
