 6→
 7→@Injectable()
 8→export class CurrencyRatesService {
 9→  @Cache({})
10→  private async _rates(
11→    baseCurrency = 'USD',
12→    { retries = 0 }: { retries?: number } = {},
13→  ) {
14→    const url = `https://api.coinbase.com/v2/exchange-rates?currency=${baseCurrency}`;
15→    const response = await fetch(url, {
16→      signal: AbortSignal.timeout(15000),
17→    });
18→
19→    if (!response.ok) {
20→      if (retries < 3) {
21→        return this._rates(baseCurrency, { retries: retries + 1 });
22→      }
23→      throw new BadRequestException(response, await response.text());
24→    }
25→
26→    const result = await response.json();
27→
28→    if (result.data.currency !== baseCurrency) {
29→      throw new BadRequestException(
30→        `Currency mismatch: expected baseCurrency = "${baseCurrency}", but received "${result.data.currency}" from API`,
31→      );
32→    }
33→
34→    return result.data;
35→  }
36→
37→  async rateInUSD(currencyCode: string): Promise<string> {
38→    if (currencyCode === 'USD') {
39→      return '1';
40→    }
41→
42→    const rates = await this._rates('USD');
43→    if (!(currencyCode in rates.rates)) {
44→      const ratesByCurrencyCode = await this._rates(currencyCode);
45→      if (!('USD' in ratesByCurrencyCode.rates)) {
46→        throw new TypeError(`Unsupported currency code: "${currencyCode}"`);
47→      }
48→
49→      rates.rates[currencyCode] = new Decimal(1).div(
50→        ratesByCurrencyCode.rates.USD,
51→      );
52→    }
53→
54→    const rate: string | undefined = rates.rates[currencyCode];
55→
56→    if (!rate || +rate <= 0 || !isNumberString(rate)) {
57→      throw new TypeError(
58→        `Invalid rate for "${currencyCode}": received "${rate}", parsed = ${+rate}`,
59→      );
60→    }
61→
62→    return rate;
63→  }
64→}
