  1→/**
  2→ * Утилиты для расчёта комиссий.
  3→ * Поддерживаются относительная (% от суммы) и абсолютная (фиксированная) части,
  4→ * а также минимальное значение комиссии.
  5→ *
  6→ * Формат строки комиссии:
  7→ *   "<relative>%+<absolute>|min=<minValue>"
  8→ * Примеры:
  9→ *   "10%" -> только 10%
 10→ *   "10%+25" -> 10% + 25 фиксировано
 11→ *   "10%+25|min=100" -> 10% + 25, но итог не меньше 100
 12→ *   "+50|min=10" -> только 50, но не меньше 10 (без процентной части)
 13→ */
 14→import Decimal from 'decimal.js';
 15→
 16→/**
 17→ * Парсит строковое представ��ение комиссии в структурированный объект.
 18→ *
 19→ * Строка может содержать:
 20→ *  - относительную часть с суффиксом % (например: 10%)
 21→ *  - абсолютную часть через + (например: +25)
 22→ *  - параметры через |, например: |min=100
 23→ *
 24→ * @param str Строка комиссии (пример: "10%+25|min=100").
 25→ * @returns Объект параметров комиссии.
 26→ * @property relative Доля (0..1) или undefined (если процент не указан).
 27→ * @property absolute Абсолютная (фиксированная) часть.
 28→ * @property min Минимально допустимая сумма комиссии.
 29→ * @property max Максимальная допустимая сумма комиссии.
 30→ */
 31→function parseCommission(str: string): {
 32→  relative: number | undefined;
 33→  absolute: number | undefined;
 34→  min: number | undefined;
 35→  max: number | undefined;
 36→} {
 37→  const [commissionStr, ..._params] = str.split('|');
 38→
 39→  // Дополнительные параметры пишем в конце строки комиссии через |
 40→  const params: Record<string, number> = _params.reduce((acc, v) => {
 41→    const [key, _value] = v.split('=');
 42→    const value = Number(_value);
 43→
 44→    if (!Number.isNaN(value)) {
 45→      acc[key] = value;
 46→    }
 47→
 48→    return acc;
 49→  }, {});
 50→
 51→  const [str1, str2] = commissionStr.split('+');
 52→  const relative = str1 ? Number(str1.replace('%', '')) / 100 : undefined;
 53→  const absolute = str2 ? Number(str2) : undefined;
 54→
 55→  return {
 56→    relative,
 57→    absolute,
 58→    min: params.min ?? undefined, // минимальная сумма комиссии можно передать как параметр пример: 10%+25|min=100
 59→    max: params.max ?? undefined, // максимальная сумма комиссии можно передать как параметр пример: 10%+25|max=100
 60→  };
 61→}
 62→
 63→/**
 64→ * Создаёт интерфейс для расчётов с комиссией относительно указанной суммы.
 65→ *
 66→ * Методы результата:
 67→ *  - only(commission?): string -> только сумма комиссии
 68→ *  - with(commission?): string -> сумма после удержания комиссии (не меньше 0)
 69→ *  - without(commission?): string -> восстановленная сумма до удержания комиссии
 70→ *
 71→ * Особенности:
 72→ *  - Если комиссия не передана: only -> '0'; with -> исходная сумма; without -> исходная сумма.
 73→ *  - Возвращаемые значения приводятся к строке (для исключения потерь точности).
 74→ *  - Все вычисления использует Decimal для корректной работы с десятичными числами.
 75→ *
 76→ * @param amount Сумма, к которой нужно применить расчёты (число или строка).
 77→ * @returns Объект с функциями only / with / without.
 78→ *
 79→ * @example
 80→ *  const c = commission(1000);
 81→ *  c.only('10%+25|min=200'); // '200' (10% = 100 + 25 = 125 < 200 -> берём min = 200)
 82→ *  c.with('10%+25|min=200'); // '800'
 83→ *  c.without('10%+25|min=200'); // сумма до удержания комиссии
 84→ */
 85→export function commission(this: unknown, amount: number | string) {
 86→  /**
 87→   * Рассчитывает только сумму комиссии.
 88→   *
 89→   * @param amount Базовая сумма.
 90→   * @param commission Строка комиссии или уже распарсенный объект.
 91→   * @returns Сумма комиссии в строковом виде.
 92→   */
 93→  const only = (
 94→    amount: number | string,
 95→    commission?: string | ReturnType<typeof parseCommission>,
 96→  ) => {
 97→    if (!commission) {
 98→      return '0';
 99→    }
100→
101→    const { relative, absolute, min, max } =
102→      typeof commission === 'string' ? parseCommission(commission) : commission;
103→
104→    let result = new Decimal(absolute || 0);
105→    if (relative) {
106→      result = result.plus(new Decimal(relative).mul(amount));
107→    }
108→
109→    return Decimal.max(
110→      min || 0,
111→      Decimal.min(result, max || Infinity),
112→    ).toString();
113→  };
114→
115→  return {
116→    /**
117→     * Возвращает только сумму комиссии.
118→     * @param commission Формат комиссии (например: "10%+25|min=200").
119→     */
120→    only: only.bind(this, amount) as (
121→      commission?: string | ReturnType<typeof parseCommission>,
122→    ) => ReturnType<typeof only>,
123→    /**
124→     * Возвращает сумму после удержания комиссии.
125→     * Если результат < 0 — возвращает '0'.
126→     * @param commission Формат комиссии. Если не указан — возвращается исходная сумма.
127→     */
128→    with: (commission?: string | ReturnType<typeof parseCommission>) => {
129→      if (+amount <= 0) {
130→        return '0';
131→      }
132→
133→      if (!commission) {
134→        return amount.toString();
135→      }
136→
137→      const result = new Decimal(amount).minus(only(amount, commission));
138→
139→      return result.lt(0) ? '0' : result.toString();
140→    },
141→    /**
142→     * Восстанавливает сумму до удержания комиссии.
143→     * Полезно, когда известна "чистая" сумма (после комиссии) и нужно получить исходную.
144→     * @param commission Формат комиссии. Если не указан — возвращается исходная сумма.
145→     */
146→    without: (commission?: string | ReturnType<typeof parseCommission>) => {
147→      if (+amount <= 0) {
148→        return '0';
149→      }
150→
151→      if (!commission) {
152→        return amount.toString();
153→      }
154→
155→      const parsedCommission =
156→        typeof commission === 'string'
157→          ? parseCommission(commission)
158→          : commission;
159→      const { relative, absolute, min, max } = parsedCommission;
160→
161→      // Если нет процентной части, то просто добавляем абсолютную часть с учётом min/max
162→      if (!relative) {
163→        const commissionAmount = Math.min(
164→          max || Infinity,
165→          Math.max(min || 0, absolute || 0),
166→        );
167→        return new Decimal(amount).plus(commissionAmount).toString();
168→      }
169→
170→      // Итеративный поиск исходной суммы для случаев с min/max ограничениями
171→      let originalAmount = new Decimal(amount)
172→        .plus(absolute || 0)
173→        .div(new Decimal(1).minus(relative));
174→
175→      // Проверяем, была ли комиссия ограничена min или max
176→      for (let iteration = 0; iteration < 10; iteration++) {
177→        const calculatedCommission = only(
178→          originalAmount.toString(),
179→          parsedCommission,
180→        );
181→        const resultAmount = originalAmount.minus(calculatedCommission);
182→
183→        // Если результат совпадает с целевой суммой, то мы нашли правильную исходную сумму
184→        if (resultAmount.equals(amount)) {
185→          return originalAmount.toString();
186→        }
187→
188→        // Корректируем исходную сумму на основе разности
189→        const difference = new Decimal(amount).minus(resultAmount);
190→        originalAmount = originalAmount.plus(difference);
191→
192→        // Если изменение слишком мало, прекращаем итерации
193→        if (difference.abs().lt(0.000001)) {
194→          break;
195→        }
196→      }
197→
198→      return originalAmount.toString();
199→    },
200→  };
201→}
202→
203→interface ICommission {
204→  /**
205→   * Возвращает только сумму комиссии.
206→   */
207→  only: () => string;
208→  /**
209→   * Возвращает сумму после удержания комиссии.
210→   * Если результат < 0 — возвращает '0'.
211→   */
212→  with: () => string;
213→  /**
214→   * Восстанавливает сумму до удержания комиссии.
215→   * Полезно, когда известна "чистая" сумма (после комиссии) и нужно получить исходную.
216→   */
217→  without: () => string;
218→  /**
219→   * Возвращает распарсенную строку комиссии.
220→   */
221→  parsedCommission: () => ReturnType<typeof parseCommission>;
222→}
223→
224→/**
225→ * Класс для расчёта комиссий.
226→ * @param amount Сумма, к которой нужно применить расчёты (число или строка).
227→ * @param commissionString Строка комиссии (пример: "10%+25|min=100").
228→ */
229→export class Commission implements ICommission {
230→  constructor(
231→    private readonly amount: number | string,
232→    private readonly commissionString: string,
233→  ) {
234→    this.rootCommision = commission(this.amount);
235→  }
236→  private rootCommision: ReturnType<typeof commission>;
237→
238→  //* Возвращает только сумму комиссии.
239→  public only() {
240→    return this.rootCommision.only(this.commissionString);
241→  }
242→
243→  public with() {
244→    return this.rootCommision.with(this.commissionString);
245→  }
246→
247→  public without() {
248→    return this.rootCommision.without(this.commissionString);
249→  }
250→
251→  public parsedCommission() {
252→    return parseCommission(this.commissionString);
253→  }
254→}
255→

