## 6. Commission System

**File: `/Users/ilyakonyaev/work/crypto/api-core/src/shared/utils/commision.ts`**

Flexible commission calculation with percentage + absolute + min/max:

```typescript
// Format: "<relative>%+<absolute>|min=<minValue>"
// Examples:
//   "10%" -> only 10%
//   "10%+25" -> 10% + 25 fixed
//   "10%+25|min=100" -> 10% + 25, but min 100
//   "+50|min=10" -> only 50, but min 10

export function commission(amount: number | string) {
  return {
    only(commissionString?): string      // Just commission amount
    with(commissionString?): string      // Amount after commission
    without(commissionString?): string   // Recover original from net amount
  }
}

export class Commission implements ICommission {
  constructor(amount: number | string, commissionString: string) {}
  public only(): string
  public with(): string
  public without(): string
  public parsedCommission(): ReturnType<typeof parseCommission>
}
```

